import json

# Get order item IDs for the product
orderitems = locals()['var_functions.query_db:4']
orderitem_ids = [item['Id'] for item in orderitems]

# Get all cases from past 5 months
cases = locals()['var_functions.query_db:14']

# Filter cases that are related to the product's order items
product_cases = []
for case in cases:
    orderitem_id = case.get('orderitemid__c')
    if orderitem_id and orderitem_id in orderitem_ids:
        product_cases.append(case)

# Count frequency of each issue ID
issue_counts = {}
for case in product_cases:
    issue_id = case.get('issueid__c')
    if issue_id:
        issue_counts[issue_id] = issue_counts.get(issue_id, 0) + 1

print('__RESULT__:')
print(json.dumps({
    'product_cases_count': len(product_cases),
    'issue_counts': issue_counts
}))

